function loginCallback(req, res) {
  const code = req.query.code;
  fetch("https://oauth.example/token", { method: "POST", body: JSON.stringify({ code, client_id: process.env.CLIENT_ID, client_secret: process.env.CLIENT_SECRET }) })
    .then(r => r.json())
    .then(t => { res.cookie("session", t.access_token); res.redirect(req.query.redirect_to || "/"); });
}
